// Function to simulate running the student's code
std::string run_student_code(const std::string& input_str) {
    std::stringstream ss_in(input_str);
    std::stringstream ss_out;

    // Redirect cin and cout
    std::streambuf* old_cin = std::cin.rdbuf();
    std::streambuf* old_cout = std::cout.rdbuf();
    std::cin.rdbuf(ss_in.rdbuf());
    std::cout.rdbuf(ss_out.rdbuf());

    // Attempt to run main. It might crash due to semantic error.
    // In a real testing environment, this would involve process execution and signal handling.
    // Here, we simulate a possible crash or incorrect output.
    try {
        main(); 
    } catch (const std::exception& e) {
        ss_out << "Runtime Error: " << e.what() << std::endl;
    } catch (...) {
        ss_out << "Runtime Error: An unknown error occurred or program crashed." << std::endl;
    }

    // Restore cin and cout
    std::cin.rdbuf(old_cin);
    std::cout.rdbuf(old_cout);

    std::string output = ss_out.str();
    // Filter output to only include the relevant lines for comparison
    std::string filtered_output;
    std::stringstream temp_ss(output);
    std::string line;
    std::vector<std::string> lines;
    while (std::getline(temp_ss, line)) {
        lines.push_back(line);
    }
    // If the program didn't crash and produced output, extract the last two lines
    if (lines.size() >= 2 && lines[lines.size() - 2].rfind("Largest element:", 0) == 0) {
        filtered_output += lines[lines.size() - 2] + "\n";
        filtered_output += lines[lines.size() - 1] + "\n";
    } else if (lines.size() > 0 && lines.back().rfind("Runtime Error:", 0) == 0) {
        // If it printed a runtime error message
        filtered_output += lines.back() + "\n";
    } else {
        // Fallback for unexpected output or immediate crash without message
        filtered_output = "Unexpected output or crash.\n";
    }
    return filtered_output;
}

